import React, { useState, useEffect } from 'react';
import Joyride, { STATUS, ACTIONS, EVENTS } from 'react-joyride';
import { useTheme } from '@mui/material';
import {
  Dashboard as DashboardIcon,
  People as UsersIcon,
  Security as SecurityIcon,
  Analytics as AnalyticsIcon,
  GetApp as ExportIcon,
  Cloud as CloudIcon,
  Settings as SettingsIcon,
  Speed as SpeedIcon
} from '@mui/icons-material';

const AdminOnboardingTour = ({ open, onClose }) => {
  const theme = useTheme();
  const [run, setRun] = useState(false);
  const [stepIndex, setStepIndex] = useState(0);

  useEffect(() => {
    if (open) {
      setRun(true);
      setStepIndex(0);
    }
  }, [open]);

  // Tour steps configuration
  const steps = [
    {
      target: 'body',
      content: (
        <div>
          <h2 style={{ marginTop: 0, color: theme.palette.primary.main }}>
            👋 Welcome to SoldiKeeper Admin Dashboard!
          </h2>
          <p>
            Let's take a quick tour of the powerful tools at your fingertips. 
            This dashboard gives you complete control over the platform.
          </p>
          <p style={{ fontSize: '0.9em', color: theme.palette.text.secondary }}>
            You can skip this tour anytime or restart it from the Help menu.
          </p>
        </div>
      ),
      placement: 'center',
      disableBeacon: true,
    },
    {
      target: '.admin-dashboard-header',
      content: (
        <div>
          <h3 style={{ marginTop: 0 }}>📊 Dashboard Header</h3>
          <p>
            Your command center shows live statistics and quick actions. 
            The dashboard updates in real-time every 30 seconds.
          </p>
        </div>
      ),
      placement: 'bottom',
    },
    {
      target: '.admin-quick-stats',
      content: (
        <div>
          <h3 style={{ marginTop: 0 }}>📈 Quick Statistics</h3>
          <p>
            Monitor key metrics at a glance: total users, transactions, 
            platform revenue, and active sessions. These update automatically!
          </p>
        </div>
      ),
      placement: 'bottom',
    },
    {
      target: '[data-tour="admin-tabs"]',
      content: (
        <div>
          <h3 style={{ marginTop: 0 }}>🗂️ Admin Tabs</h3>
          <p>
            Navigate through 13 specialized sections covering everything from 
            user management to AI-powered insights. Each tab is optimized 
            for its specific task.
          </p>
        </div>
      ),
      placement: 'bottom',
    },
    {
      target: '[data-tab="users"]',
      content: (
        <div>
          <h3 style={{ marginTop: 0 }}>👥 User Management</h3>
          <p>
            Manage all platform users here. You can view details, suspend accounts, 
            assign roles (RBAC), and track user activity with advanced filtering.
          </p>
        </div>
      ),
      placement: 'bottom',
    },
    {
      target: '[data-tab="transactions"]',
      content: (
        <div>
          <h3 style={{ marginTop: 0 }}>💳 Transaction Monitor</h3>
          <p>
            Real-time transaction monitoring with powerful search and filtering. 
            Track all financial activities across the platform.
          </p>
        </div>
      ),
      placement: 'bottom',
    },
    {
      target: '[data-tab="analytics"]',
      content: (
        <div>
          <h3 style={{ marginTop: 0 }}>📊 Analytics & Reports</h3>
          <p>
            Comprehensive analytics with beautiful visualizations. Generate 
            reports on user behavior, financial trends, and platform performance.
          </p>
        </div>
      ),
      placement: 'bottom',
    },
    {
      target: '[data-tab="security"]',
      content: (
        <div>
          <h3 style={{ marginTop: 0 }}>🔒 Security Center</h3>
          <p>
            Your security command center. Monitor suspicious activity, 
            block IPs, configure alerts, and review audit logs.
          </p>
        </div>
      ),
      placement: 'bottom',
    },
    {
      target: '[data-action="export"]',
      content: (
        <div>
          <h3 style={{ marginTop: 0 }}>💾 Export Data</h3>
          <p>
            Export dashboard data in multiple formats (PDF, Excel, CSV) 
            for reporting and compliance purposes.
          </p>
        </div>
      ),
      placement: 'left',
    },
    {
      target: '[data-indicator="websocket"]',
      content: (
        <div>
          <h3 style={{ marginTop: 0 }}>🔴 Real-Time Status</h3>
          <p>
            This indicator shows your WebSocket connection status. 
            Green = Live updates active. Red = Reconnecting.
          </p>
        </div>
      ),
      placement: 'bottom',
    },
    {
      target: '[data-tab="settings"]',
      content: (
        <div>
          <h3 style={{ marginTop: 0 }}>⚙️ System Settings</h3>
          <p>
            Configure platform-wide settings, manage integrations, 
            and customize the admin experience.
          </p>
        </div>
      ),
      placement: 'bottom',
    },
    {
      target: 'body',
      content: (
        <div>
          <h2 style={{ marginTop: 0, color: theme.palette.success.main }}>
            🎉 You're All Set!
          </h2>
          <p>
            You now know the basics of the Admin Dashboard. Explore each 
            section to discover more powerful features.
          </p>
          <p style={{ fontSize: '0.9em', color: theme.palette.text.secondary }}>
            💡 <strong>Pro Tip:</strong> Hover over any icon or button to see 
            helpful tooltips. You can restart this tour anytime from the Help menu.
          </p>
        </div>
      ),
      placement: 'center',
    },
  ];

  // Handle tour callback
  const handleJoyrideCallback = (data) => {
    const { status, type, action, index } = data;

    // Update step index for controlled tour
    if ([EVENTS.STEP_AFTER, EVENTS.TARGET_NOT_FOUND].includes(type)) {
      setStepIndex(index + (action === ACTIONS.PREV ? -1 : 1));
    }

    // Handle tour completion or skip
    if ([STATUS.FINISHED, STATUS.SKIPPED].includes(status)) {
      setRun(false);

      // Mark tour as completed in localStorage
      localStorage.setItem('admin_tour_completed', 'true');
      localStorage.setItem('admin_tour_completed_date', new Date().toISOString());

      // Call onClose callback
      if (onClose) {
        onClose();
      }
    }
  };

  // Custom styles matching SoldiKeeper theme
  const joyrideStyles = {
    options: {
      arrowColor: theme.palette.mode === 'dark' ? '#1e293b' : '#ffffff',
      backgroundColor: theme.palette.mode === 'dark' ? '#1e293b' : '#ffffff',
      overlayColor: theme.palette.mode === 'dark' ? 'rgba(0, 0, 0, 0.7)' : 'rgba(0, 0, 0, 0.5)',
      primaryColor: theme.palette.primary.main,
      textColor: theme.palette.text.primary,
      width: 380,
      zIndex: 10000,
    },
    tooltip: {
      borderRadius: 12,
      padding: 20,
      boxShadow: theme.shadows[12],
      fontSize: 15,
      lineHeight: 1.6,
    },
    tooltipContainer: {
      textAlign: 'left',
    },
    tooltipTitle: {
      fontSize: 18,
      fontWeight: 600,
      marginBottom: 8,
    },
    tooltipContent: {
      padding: '12px 0',
    },
    buttonNext: {
      backgroundColor: theme.palette.primary.main,
      borderRadius: 8,
      padding: '10px 20px',
      fontSize: 14,
      fontWeight: 600,
      outline: 'none',
      border: 'none',
    },
    buttonBack: {
      color: theme.palette.text.secondary,
      marginLeft: 0,
      marginRight: 10,
      fontSize: 14,
    },
    buttonSkip: {
      color: theme.palette.text.secondary,
      fontSize: 14,
    },
    buttonClose: {
      display: 'none', // Hide close button, use Skip instead
    },
    beacon: {
      outline: 'none',
    },
    beaconInner: {
      backgroundColor: theme.palette.primary.main,
    },
    beaconOuter: {
      backgroundColor: `${theme.palette.primary.main}33`,
      border: `2px solid ${theme.palette.primary.main}`,
    },
    spotlight: {
      borderRadius: 8,
    },
  };

  return (
    <Joyride
      steps={steps}
      run={run}
      continuous
      showProgress
      showSkipButton
      stepIndex={stepIndex}
      callback={handleJoyrideCallback}
      styles={joyrideStyles}
      locale={{
        back: 'Back',
        close: 'Close',
        last: 'Finish',
        next: 'Next',
        skip: 'Skip Tour',
      }}
      floaterProps={{
        disableAnimation: false,
        styles: {
          floater: {
            filter: 'drop-shadow(0 10px 20px rgba(0,0,0,0.3))',
          },
        },
      }}
      scrollToFirstStep
      scrollOffset={100}
      disableOverlayClose
      disableCloseOnEsc={false}
      spotlightPadding={8}
    />
  );
};

export default AdminOnboardingTour;
